SELECT * FROM selection_apply
WHERE is_deleted = 0

    AND user_id = #{pageDTO.userId}


    AND spu_id = #{pageDTO.spuId}


    AND shop_id = #{pageDTO.shopId}


    AND audit_status = #{pageDTO.auditStatus}


    AND apply_time >= #{pageDTO.startTime}


    AND apply_time <= #{pageDTO.endTime}

ORDER BY apply_time DESC

SELECT COUNT(*) FROM selection_apply
WHERE is_deleted = 0

    AND user_id = #{pageDTO.userId}


    AND spu_id = #{pageDTO.spuId}


    AND shop_id = #{pageDTO.shopId}


    AND audit_status = #{pageDTO.auditStatus}


    AND apply_time >= #{pageDTO.startTime}


    AND apply_time <= #{pageDTO.endTime}

SELECT * FROM selection_apply
WHERE user_id = #{userId}
  AND spu_id = #{spuId}
  AND is_deleted = 0
  AND audit_status IN (1, 2)
LIMIT 1

SELECT * FROM selection_apply
WHERE user_id = #{userId}
  AND is_deleted = 0
ORDER BY apply_time DESC
LIMIT #{pageNum}, #{pageSize}

SELECT COUNT(*) FROM selection_apply
WHERE user_id = #{userId}
  AND is_deleted = 0
